        StringAssert.DoesNotMatch(result, new(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Trailing Dashes---");

        StringAssert.DoesNotMatch(result, new(@"-$"));
    }

