    public void GenerateSlug_MixedCase_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("My Blog Post");

        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("too   many   spaces");

        Assert.AreEqual("too-many-spaces", result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

